 1	import * as React from 'react';
 2	import {
 3	  InputGroup,
 4	  InputGroupText,
 5	  Spinner,
 6	  TextInput,
 7	} from '@patternfly/react-core';
 8	import { useTranslation } from 'react-i18next';
 9	import QuickSearchIcon from './QuickSearchIcon';
10	import './QuickSearchBar.scss';
11	
12	interface QuickSearchBarProps {
13	  showNoResults: boolean;
14	  itemsLoaded: boolean;
15	  autoFocus: boolean;
16	  searchTerm: string;
17	  onSearch: (
18	    event: React.FormEvent<HTMLInputElement>,
19	    searchTerm: string,
20	  ) => void;
21	  searchPlaceholder: string;
22	  icon?: React.ReactNode;
23	}
24	
25	const QuickSearchBar: React.FC<QuickSearchBarProps> = ({
26	  showNoResults,
27	  itemsLoaded,
28	  autoFocus = false,
29	  searchTerm,
30	  searchPlaceholder,
31	  onSearch,
32	  icon,
33	}) => {
34	  const { t } = useTranslation('plugin__pipelines-console-plugin');
35	  const inputRef = React.useRef<HTMLInputElement>(null);
36	  const spanRef = React.useRef<HTMLSpanElement>(null);
37	  return (
38	    <InputGroup
39	      onClick={() => inputRef.current?.focus()}
40	      className="ocs-quick-search-bar"
41	      data-test="quick-search-bar"
42	    >
43	      <InputGroupText className="ocs-quick-search-bar__icon ocs-quick-search-bar__border-none">
44	        {icon || <QuickSearchIcon />}
45	      </InputGroupText>
46	      <div className="ocs-quick-search-bar__input-wrapper">
47	        {/* <span> is only used to calculate the width of input based on the text in search */}
48	        <span className="ocs-quick-search-bar__input-dummy" ref={spanRef}>
49	          {searchTerm?.length >= searchPlaceholder.length
50	            ? searchTerm.replace(/ /g, '\u00a0')
51	            : searchPlaceholder}
52	        </span>
53	        <TextInput
54	          type="text"
55	          ref={inputRef}
56	          aria-label={t('Quick search bar')}
57	          className="ocs-quick-search-bar__input"
58	          placeholder={searchPlaceholder}
59	          onChange={onSearch}
60	          autoFocus={autoFocus}
61	          value={searchTerm}
62	          data-test="input"
63	          style={{
64	            width: spanRef.current?.offsetWidth
65	              ? spanRef.current?.offsetWidth + 2
66	              : '0px',
67	          }}
68	        />
69	        {itemsLoaded && showNoResults && (
70	          <InputGroupText
71	            className="ocs-quick-search-bar__no-results ocs-quick-search-bar__border-none"
72	            data-test="quick-search-no-results"
73	          >
74	            &mdash; {t('No results')}
75	          </InputGroupText>
76	        )}
77	      </div>
78	      {!itemsLoaded && (
79	        <InputGroupText className="ocs-quick-search-bar__border-none ocs-quick-search-bar__spinner">
80	          <Spinner size="lg" />
81	        </InputGroupText>
82	      )}
83	    </InputGroup>
84	  );
85	};
86	
87	export default QuickSearchBar;

